SELECT [DDT_Picking Line].[Line No_] AS Line, [DDT_Picking Header].No_ AS OrderNumber, "DK" AS Type, "" AS OrderReference, [DDT_Picking Header].[Posting Date] AS OrderDate, "" AS InvoceDate, [DDT_Picking Header].[Ship-to Name] AS ShipToName, [DDT_Picking Header].[Ship-to Address] AS ShipToAdrress, [DDT_Picking Header].[Ship-to Address 2] AS ShipToAdrress2, [DDT_Picking Header].[Ship-to City] AS ShipToCity, [DDT_Picking Header].[Ship-to County] AS ShipToState, [DDT_Picking Header].[Ship-to Country_Region Code] AS ShipToCountry, [DDT_Picking Header].[Ship-to Post Code] AS ShipToZip, "" AS email, "" AS phone, [Item.Model Item No_] & "_" & [Item.Variable Code 01] & "_" & [Item.Variable Code 02] AS ItemCode, Val([quantity]) AS Qty, "" AS Carrier, "" AS Notes
FROM ([DDT_Picking Line] INNER JOIN [DDT_Picking Header] ON [DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_) INNER JOIN Item ON [DDT_Picking Line].No_ = Item.No_
WHERE ((([DDT_Picking Header].No_)="SPD-22/16456") AND (([DDT_Picking Line].Type)=2));

